1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Scenario = { steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	const COMPONENT_BASE_PER_ITEM = 25;
6	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	export function runScenario(input: unknown): unknown {
16	  const { steps } = input as Scenario;
17	  const premium = computePremium(steps[0].items);
18	  return { results: [{ premium }] };
19	}
20	
21	function computePremium(items: Item[]): number {
22	  if (items.length === 0) return PROCESSING_FEE;
23	  if (items.every(isComponent)) return componentsPremium(items);
24	  return singleItemPremium(items[0]);
25	}
26	
27	function singleItemPremium(item: Item): number {
28	  const base = BASE_PREMIUM_BY_TYPE[item.type];
29	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
30	  const highEnchSurcharge = isHighlyEnchanted(item) ? base * 0.3 : 0;
31	  const firstInsuranceMarkup = base * 0.1;
32	  return Math.ceil(base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup) + PROCESSING_FEE;
33	}
34	
35	function isHighlyEnchanted(item: Item): boolean {
36	  return (item.enchantment ?? 0) >= 5;
37	}
38	
39	function componentsPremium(items: Item[]): number {
40	  const runes = items.filter((i) => i.type === "rune").length;
41	  const moonstones = items.filter((i) => i.type === "moonstone").length;
42	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
43	}
44	
45	function componentTypeBase(count: number): number {
46	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
47	}
48	
49	function isComponent(item: Item): boolean {
50	  return item.type === "rune" || item.type === "moonstone";
51	}
52	
53	function premiumFromBase(base: number): number {
54	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
55	}
